function pollScanStatus() {
    const timer = setInterval(async () => {
        try {
            const response = await fetch('\x2f\x61\x70\x69\x2f\x73\x74\x61\x74\x75\x73');
            const data = await response.json();
            document.getElementById('\x73\x63\x61\x6e\x2d\x70\x72\x6f\x67\x72\x65\x73\x73\x2d\x62\x61\x72').style.width = `${data.progress}%`;
            document.getElementById('\x73\x63\x61\x6e\x2d\x70\x72\x6f\x67\x72\x65\x73\x73\x2d\x70\x63\x74').textContent = `${data.progress}%`;
            document.getElementById('\x73\x63\x61\x6e\x2d\x70\x72\x6f\x67\x72\x65\x73\x73\x2d\x63\x6f\x75\x6e\x74').textContent = `${data.stats.raw_count + data.stats.jpg_count} / ${data.total_files} files`;
            const fileText = translations[appState.language].analyzing;
            document.getElementById('\x73\x63\x61\x6e\x6e\x69\x6e\x67\x2d\x63\x75\x72\x72\x65\x6e\x74\x2d\x66\x69\x6c\x65').textContent = data.current_file ? `${fileText}: ${data.current_file}` : translations[appState.language].preparing_pipeline;
            document.getElementById('\x6c\x69\x76\x65\x2d\x73\x74\x61\x74\x2d\x72\x61\x77').textContent = data.stats.raw_count;
            document.getElementById('\x6c\x69\x76\x65\x2d\x73\x74\x61\x74\x2d\x6a\x70\x67').textContent = data.stats.jpg_count;
            document.getElementById('\x6c\x69\x76\x65\x2d\x73\x74\x61\x74\x2d\x67\x72\x6f\x75\x70\x73').textContent = data.stats.group_count;
            if (!data.is_running && (data.progress >= 100 || data.total_files === 0)) {
                clearInterval(timer);
                await fetchAndRenderResults();
            }
        } catch (err) {
            console.error('\x45\x72\x72\x6f\x72\x20\x70\x6f\x6c\x6c\x69\x6e\x67\x20\x73\x74\x61\x74\x75\x73\x3a', err);
            clearInterval(timer);
            alert(translations[appState.language].connecting_err);
            showScreen('\x73\x65\x74\x75\x70');
        }
    }, 500);
}
async function fetchAndRenderResults() {
    try {
        const response = await fetch('\x2f\x61\x70\x69\x2f\x72\x65\x73\x75\x6c\x74\x73');
        const results = await response.json();
        appState.results = results;
        appState.scenes = {};
        results.forEach(item => {
            const gid = item.group_id;
            if (!appState.scenes[gid]) {
                appState.scenes[gid] = [];
            }
            appState.scenes[gid].push(item);
        });
        updateHeaderStats();
        renderSidebar();
        const groupIds = Object.keys(appState.scenes);
        if (groupIds.length > 0) {
            selectGroup(groupIds[0]);
        }
        showScreen('\x64\x61\x73\x68\x62\x6f\x61\x72\x64');
    } catch (err) {
        alert(`${translations[appState.language].network_err}: ${err.message}`);
        showScreen('\x73\x65\x74\x75\x70');
    }
}
function updateHeaderStats() {
    const results = appState.results;
    const rawCount = results.filter(i => i.metadata.file_type === '\x52\x41\x57').length;
    const jpgCount = results.filter(i => i.metadata.file_type === '\x4a\x50\x45\x47').length;
    const keepCount = results.filter(i => i.decision === '\x4b\x65\x65\x70').length;
    const rejectCount = results.filter(i => i.decision === '\x52\x65\x6a\x65\x63\x74').length;
    document.getElementById('\x73\x74\x61\x74\x2d\x74\x6f\x74\x61\x6c').textContent = results.length;
    document.getElementById('\x73\x74\x61\x74\x2d\x72\x61\x74\x69\x6f').textContent = `${rawCount} RAW / ${jpgCount} JPG`;
    document.getElementById('\x73\x74\x61\x74\x2d\x67\x72\x6f\x75\x70\x73').textContent = Object.keys(appState.scenes).length;
    document.getElementById('\x73\x74\x61\x74\x2d\x6b\x65\x65\x70').textContent = keepCount;
    document.getElementById('\x73\x74\x61\x74\x2d\x72\x65\x6a\x65\x63\x74').textContent = rejectCount;
}
