            document.getElementById('\x63\x6f\x70\x79\x2d\x70\x72\x6f\x67\x72\x65\x73\x73\x2d\x70\x63\x74').textContent = `${data.progress}%`;
            document.getElementById('\x63\x6f\x70\x79\x2d\x70\x72\x6f\x67\x72\x65\x73\x73\x2d\x63\x6f\x75\x6e\x74').textContent = `${data.copied_files} / ${data.total_files} file`;
            document.getElementById('\x63\x6f\x70\x79\x2d\x63\x75\x72\x72\x65\x6e\x74\x2d\x66\x69\x6c\x65').textContent = data.current_file 
