function generateReport() {
    const results = appState.results;
    if (results.length === 0) return;
    const total = results.length;
    const keep = results.filter(i => i.decision === '\x4b\x65\x65\x70').length;
    const reject = total - keep;
    const keepPct = Math.round((keep / total) * 100);
    document.getElementById('\x72\x65\x70\x2d\x74\x6f\x74\x61\x6c').textContent = total;
    document.getElementById('\x72\x65\x70\x2d\x6b\x65\x65\x70').textContent = keep;
    document.getElementById('\x72\x65\x70\x2d\x72\x65\x6a\x65\x63\x74').textContent = reject;
    document.getElementById('\x72\x65\x70\x2d\x70\x63\x74').textContent = `${keepPct}%`;
    let blurCount = 0;
    let eyesClosedCount = 0;
    let exposureCount = 0;
    let duplicateCount = 0;
    results.forEach(item => {
        if (item.decision === '\x52\x65\x6a\x65\x63\x74') {
            const analysis = item.analysis;
            if (!item.is_best_in_group) {
                duplicateCount++;
            } else {
                if (analysis.is_blurry) {
                    blurCount++;
                } else if (analysis.is_eyes_closed) {
                    eyesClosedCount++;
                } else if (analysis.exposure_status !== '\x4e\x6f\x72\x6d\x61\x6c' && !analysis.raw_recoverable) {
                    exposureCount++;
                } else {
                    duplicateCount++;
                }
            }
        }
    });
    const countText = appState.language === '\x76\x69' ? '\x66\x69\x6c\x65' : '\x66\x69\x6c\x65\x73';
    document.getElementById('\x72\x65\x70\x2d\x72\x65\x61\x73\x6f\x6e\x2d\x62\x6c\x75\x72').textContent = `${blurCount} ${countText}`;
    document.getElementById('\x72\x65\x70\x2d\x72\x65\x61\x73\x6f\x6e\x2d\x65\x79\x65\x73').textContent = `${eyesClosedCount} ${countText}`;
    document.getElementById('\x72\x65\x70\x2d\x72\x65\x61\x73\x6f\x6e\x2d\x65\x78\x70\x6f\x73\x75\x72\x65').textContent = `${exposureCount} ${countText}`;
    document.getElementById('\x72\x65\x70\x2d\x72\x65\x61\x73\x6f\x6e\x2d\x64\x75\x70\x6c\x69\x63\x61\x74\x65').textContent = `${duplicateCount} ${countText}`;
}
async function adjustKeepRate(keepRate) {
    if (appState.results.length === 0) return;
    try {
        const response = await fetch('\x2f\x61\x70\x69\x2f\x61\x64\x6a\x75\x73\x74\x5f\x6b\x65\x65\x70\x5f\x72\x61\x74\x65', {
            method: '\x50\x4f\x53\x54',
            headers: { '\x43\x6f\x6e\x74\x65\x6e\x74\x2d\x54\x79\x70\x65': '\x61\x70\x70\x6c\x69\x63\x61\x74\x69\x6f\x6e\x2f\x6a\x73\x6f\x6e' },
            body: JSON.stringify({ keep_rate: keepRate })
        });
        if (!response.ok) {
            console.error('\x46\x61\x69\x6c\x65\x64\x20\x74\x6f\x20\x61\x64\x6a\x75\x73\x74\x20\x6b\x65\x65\x70\x20\x72\x61\x74\x65\x20\x69\x6e\x20\x62\x61\x63\x6b\x65\x6e\x64');
            return;
        }
        const results = await response.json();
        appState.results = results;
        appState.scenes = {};
        results.forEach(item => {
            const gid = item.group_id;
            if (!appState.scenes[gid]) {
                appState.scenes[gid] = [];
            }
            appState.scenes[gid].push(item);
        });
        updateHeaderStats();
        renderSidebar();
        if (appState.activeGroupId) {
            selectGroup(appState.activeGroupId);
        }
    } catch (err) {
        console.error('\x45\x72\x72\x6f\x72\x20\x61\x64\x6a\x75\x73\x74\x69\x6e\x67\x20\x6b\x65\x65\x70\x20\x72\x61\x74\x65\x3a', err);
    }
}
